void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("sailor5_1");			link.l1 = StringFromKey("sailor5_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("sailor5_3");			link.l1 = StringFromKey("sailor5_4");			link.l1.go = "2";		break;		case "2":			dialog.text = StringFromKey("sailor5_5");			link.l1 = "...";			link.l1.go = "exit";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}